T_csl_allocation_id QMAN_allocate_bc(T_QMAN_task_descriptor* queue, uint8_t absolute_priority, uint16_t queue_size )
#endif // #if defined(SENSPRO)
	{
		uint32_t qman_num, allocation_id = 0;
        T_csl_allocation_id return_value = ( T_csl_allocation_id )CSL_ALLOCATION_FAILURE;

		#if defined(SENSPRO)

			#ifdef CEVA
				if(!QMAN_is_all_paused())
				{
					CSL_ASSERT_FUNC_CALL( QMAN_pause_all() );
					while(CSL_FALSE == QMAN_is_all_paused())
					{

					}
				}
			#endif /* CEVA */

			allocation_id = QMAN_allocate(queue, absolute_priority, queue_size, continuous_mode);

		#else // ! SENSPRO
			allocation_id = QMAN_allocate(queue, absolute_priority, queue_size);
		#endif // defined(SENSPRO)


			if( ( T_csl_allocation_id )CSL_ALLOCATION_FAILURE != allocation_id )
			{
				qman_num =  CSL_GET_RESOURCE_NUM( allocation_id );
				#ifdef CEVA
					g_qman_resource[qman_num].allocation_id = qman_num;
				#endif /* CEVA */

				return_value = g_qman_resource[qman_num].allocation_id;
			}

			#if defined(SENSPRO) && defined(CEVA)
				CSL_ASSERT_FUNC_CALL( QMAN_resume_all() );
			#endif // defined(SENSPRO) && defined(CEVA)

		return return_value;
	}
